import{_ as t,o as s,c as r,a2 as o}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Summary","description":"Consolidate the testing strategies into a comprehensive test plan that gives confidence in agent correctness without excessive API costs.","frontmatter":{"title":"Summary","description":"Consolidate the testing strategies into a comprehensive test plan that gives confidence in agent correctness without excessive API costs."},"headers":[],"relativePath":"learn/linear/16-testing-coding-agents/12-summary.md","filePath":"learn/linear/16-testing-coding-agents/12-summary.md"}'),a={name:"learn/linear/16-testing-coding-agents/12-summary.md"};function i(n,e,c,d,h,l){return s(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How unit tests, mocks, snapshots, property tests, recording/replay, and benchmarks compose into a complete agent testing strategy</li><li>A decision framework for choosing the right testing technique for each type of agent behavior you need to verify</li><li>How to maintain and evolve your test suite as the agent grows, models change, and new features are added</li></ul></blockquote><p>You have now covered the full spectrum of testing techniques for a coding agent. Each technique addresses a specific challenge, and together they form a comprehensive strategy that gives you confidence in your agent&#39;s correctness without draining your API budget. Let&#39;s bring it all together.</p><h2 id="the-complete-testing-strategy" tabindex="-1">The Complete Testing Strategy <a class="header-anchor" href="#the-complete-testing-strategy" aria-label="Permalink to &quot;The Complete Testing Strategy&quot;">​</a></h2><p>Here is every technique from this chapter and where it fits in your agent&#39;s test suite:</p><p><strong>Unit tests</strong> cover your deterministic code: tool implementations, parsers, validators, formatters, token counters, and configuration loaders. These are your foundation — they run in milliseconds, catch the most bugs, and cost nothing. You should have hundreds of them.</p><p><strong>Mock providers</strong> let you test the agentic loop without calling real APIs. You script LLM responses and verify that your loop dispatches tools correctly, handles errors, manages turn limits, and constructs proper conversation histories. These tests run in seconds and cover your critical code paths.</p><p><strong>Snapshot tests</strong> catch unintended changes in outputs that matter: tool result formatting, API request bodies, system prompts, and error messages. They are not for testing correctness — they are for detecting change. Use them for outputs consumed by external systems (the LLM, the API, the user).</p><p><strong>Property-based tests</strong> explore the space of inputs your code might encounter. They verify invariants like &quot;parsing never panics,&quot; &quot;path validation always rejects traversal,&quot; and &quot;token counting never decreases when messages are added.&quot; They catch the edge cases you would never think to write by hand.</p><p><strong>Recording and replay</strong> bridges the gap between mocked tests and reality. You record a real API interaction once, sanitize it, and replay it in your test suite forever. This gives you real-world fidelity at test-suite speed. Re-record when you change models, prompts, or tools.</p><p><strong>Benchmark evaluations</strong> measure what actually matters: can the agent complete real coding tasks? They call the real API, so they are expensive and non-deterministic. Run them on a schedule or before releases, and track results over time to detect regressions.</p><p><strong>Safety tests</strong> verify that your security boundaries hold under adversarial conditions. They test path traversal prevention, command injection blocking, permission enforcement, and prompt injection defense. They run on every commit and are never skipped.</p><p><strong>Test fixtures</strong> provide the reusable building blocks that make all the above tests clean and maintainable. Workspace fixtures scaffold temp directories, conversation fixtures set up mock interactions, and data fixtures load recordings and expected outputs.</p><h2 id="decision-framework-which-technique-for-which-behavior" tabindex="-1">Decision Framework: Which Technique for Which Behavior <a class="header-anchor" href="#decision-framework-which-technique-for-which-behavior" aria-label="Permalink to &quot;Decision Framework: Which Technique for Which Behavior&quot;">​</a></h2><p>When you need to test something new, use this decision framework:</p><table tabindex="0"><thead><tr><th>What you are testing</th><th>Technique</th><th>Why</th></tr></thead><tbody><tr><td>A tool&#39;s core logic (read, write, shell)</td><td>Unit test with real temp directory</td><td>Deterministic, fast, tests the real thing</td></tr><tr><td>Input validation for tool arguments</td><td>Unit test + property test</td><td>Unit test for known cases, property test for edge cases</td></tr><tr><td>Agentic loop flow (tool dispatch, turn management)</td><td>Integration test with mock provider</td><td>Tests the loop without API costs</td></tr><tr><td>Error recovery (tool fails, model retries)</td><td>Integration test with scripted mock</td><td>Script the failure and recovery sequence</td></tr><tr><td>Output formatting (what the LLM sees)</td><td>Snapshot test</td><td>Detects any change in formatting</td></tr><tr><td>API request construction</td><td>Snapshot test with redactions</td><td>Catches field changes, ignores dynamic values</td></tr><tr><td>Security boundaries</td><td>Dedicated safety test suite</td><td>Must run on every commit, never skipped</td></tr><tr><td>Parser robustness</td><td>Property test</td><td>Explores random inputs, catches panics</td></tr><tr><td>Real-world agent quality</td><td>Benchmark evaluation</td><td>Expensive but necessary ground truth</td></tr><tr><td>Prompt changes</td><td>Replay test (before change) + benchmark (after)</td><td>Replay verifies no regression, benchmark measures improvement</td></tr></tbody></table><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you are coming from pytest, here is how Rust&#39;s testing tools map to what you know:</p><table tabindex="0"><thead><tr><th>Python (pytest)</th><th>Rust equivalent</th></tr></thead><tbody><tr><td><code>def test_foo():</code></td><td><code>#[test] fn test_foo()</code></td></tr><tr><td><code>@pytest.fixture</code></td><td>Helper function or builder struct</td></tr><tr><td><code>@pytest.mark.parametrize</code></td><td><code>test-case</code> crate or loop in test</td></tr><tr><td><code>unittest.mock.MagicMock</code></td><td>Implement the trait yourself (<code>MockProvider</code>)</td></tr><tr><td><code>pytest-snapshot</code> / <code>syrupy</code></td><td><code>insta</code> crate</td></tr><tr><td><code>hypothesis</code></td><td><code>proptest</code> crate</td></tr><tr><td><code>vcrpy</code> (HTTP recording)</td><td>Custom <code>RecordingProvider</code> / <code>ReplayProvider</code></td></tr><tr><td><code>pytest.mark.slow</code></td><td><code>#[ignore]</code> attribute</td></tr><tr><td><code>conftest.py</code></td><td><code>tests/common/mod.rs</code> or test helper module</td></tr><tr><td><code>pytest -m &quot;not slow&quot;</code></td><td><code>cargo test</code> (ignores <code>#[ignore]</code> by default)</td></tr><tr><td><code>pytest -m slow</code></td><td><code>cargo test -- --ignored</code></td></tr><tr><td><code>tox</code> / <code>nox</code></td><td>GitHub Actions workflow tiers</td></tr></tbody></table><p>The biggest conceptual difference: Python fixtures are injected by name (the framework resolves them), while Rust fixtures are called explicitly (you construct them yourself). Rust&#39;s approach is more verbose but more transparent — there is no hidden resolution order or scope confusion.</p></div><h2 id="the-ci-pipeline-recap" tabindex="-1">The CI Pipeline Recap <a class="header-anchor" href="#the-ci-pipeline-recap" aria-label="Permalink to &quot;The CI Pipeline Recap&quot;">​</a></h2><p>Your CI pipeline runs these tests in three tiers:</p><p><strong>Every push</strong> (seconds):</p><ul><li>All unit tests (<code>cargo test --lib</code>)</li><li>All safety tests</li><li>Property tests</li><li>Clippy and formatting checks</li></ul><p><strong>Every pull request</strong> (minutes):</p><ul><li>Everything from Tier 1</li><li>Integration tests with mock providers (<code>cargo test --test &#39;*&#39;</code>)</li><li>Replay tests using recorded fixtures</li><li>Snapshot verification</li></ul><p><strong>Scheduled or release</strong> (minutes, costs money):</p><ul><li>Everything from Tiers 1 and 2</li><li>Benchmark evaluations against real API (<code>cargo test -- --ignored</code>)</li><li>Results saved as artifacts for trend tracking</li></ul><h2 id="evolving-your-test-suite" tabindex="-1">Evolving Your Test Suite <a class="header-anchor" href="#evolving-your-test-suite" aria-label="Permalink to &quot;Evolving Your Test Suite&quot;">​</a></h2><p>Your test suite is not static. It grows and changes with your agent. Here is how to keep it healthy:</p><p><strong>When you add a new tool:</strong> Write unit tests for input validation, execution, error handling, and output formatting. Add the tool to existing integration test scenarios where appropriate. Add safety tests if the tool interacts with the filesystem or shell.</p><p><strong>When you change the system prompt:</strong> Run existing replay tests to see if the change breaks any recorded interactions. If it does, evaluate whether the break is acceptable. Run benchmarks to measure whether the change improves task completion. Re-record affected fixtures.</p><p><strong>When you switch models:</strong> Re-record all replay fixtures with the new model. Run the full benchmark suite and compare results to the previous model. Watch for changes in tool calling patterns — a new model might use tools differently.</p><p><strong>When you find a bug in production:</strong> Write a unit or integration test that reproduces the bug before fixing it. This becomes a regression test that prevents the bug from returning. If the bug was a security issue, add it to the safety test suite.</p><p><strong>When tests become slow:</strong> Profile which tests take the longest. Move slow-but-important tests behind <code>#[ignore]</code>. Look for tests that create unnecessary temp directories or run redundant setup. Consider sharing workspace fixtures across related tests using <code>lazy_static</code> or <code>once_cell</code>.</p><h2 id="what-you-built-in-this-chapter" tabindex="-1">What You Built in This Chapter <a class="header-anchor" href="#what-you-built-in-this-chapter" aria-label="Permalink to &quot;What You Built in This Chapter&quot;">​</a></h2><p>Over these twelve subchapters, you built a complete testing infrastructure:</p><ol><li>A <strong>testing philosophy</strong> that separates deterministic from non-deterministic code and tests each appropriately</li><li><strong>Unit tests</strong> for every tool covering validation, execution, errors, and formatting</li><li>A <strong>mock provider</strong> with response builders for fast, deterministic loop testing</li><li><strong>Integration tests</strong> that verify the full agentic loop including tool dispatch and error recovery</li><li><strong>Snapshot tests</strong> that catch unintended changes in tool output formatting and API requests</li><li><strong>Property-based tests</strong> that explore edge cases in parsers, validators, and data transformations</li><li>A <strong>recording and replay</strong> system that captures real API interactions for test fixtures</li><li><strong>Benchmark tasks</strong> with success criteria and scoring for measuring real-world agent quality</li><li>A <strong>safety test suite</strong> that verifies security boundaries under adversarial conditions</li><li>A <strong>CI/CD pipeline</strong> with three tiers that balances coverage, speed, and cost</li><li><strong>Reusable test fixtures</strong> for workspaces, conversations, and fixture data</li></ol><p>This testing infrastructure lets you iterate on your agent with confidence. You can change prompts, swap models, add tools, and refactor code knowing that your test suite will catch regressions in correctness, security, and quality.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>The most successful production coding agents — Claude Code, Cursor, and similar tools — all invest heavily in testing infrastructure. They maintain thousands of deterministic tests for their tool implementations and core logic, hundreds of mock-based integration tests for conversation flows, and curated benchmark suites that measure real-world task completion. The common lesson: the testing infrastructure is as important as the agent code itself. Spending a week building good test fixtures, mock providers, and CI pipelines pays for itself many times over in bugs caught before they reach users.</p></div><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><h3 id="exercise-1-testing-strategy-for-a-non-deterministic-feature-medium" tabindex="-1">Exercise 1: Testing Strategy for a Non-Deterministic Feature (Medium) <a class="header-anchor" href="#exercise-1-testing-strategy-for-a-non-deterministic-feature-medium" aria-label="Permalink to &quot;Exercise 1: Testing Strategy for a Non-Deterministic Feature (Medium)&quot;">​</a></h3><p>Your agent has a &quot;smart commit message&quot; feature that generates commit messages from diffs using the LLM. The output varies between runs even with the same input. Design a testing strategy that gives you confidence in this feature without requiring exact output matching. Consider: what properties should every generated commit message satisfy (length, format, content relevance)? How would you write a property-based test for this? How would you use recording/replay to create a regression suite? What would a benchmark evaluation for commit message quality look like -- what scoring criteria would you use?</p><h3 id="exercise-2-mock-provider-design-for-edge-cases-easy" tabindex="-1">Exercise 2: Mock Provider Design for Edge Cases (Easy) <a class="header-anchor" href="#exercise-2-mock-provider-design-for-edge-cases-easy" aria-label="Permalink to &quot;Exercise 2: Mock Provider Design for Edge Cases (Easy)&quot;">​</a></h3><p>Design a <code>MockProvider</code> configuration that simulates three failure scenarios: (a) the model returns a tool call with malformed JSON arguments, (b) the model enters an infinite loop calling the same tool repeatedly, and (c) the model&#39;s response is cut off mid-stream due to a connection drop. For each scenario, describe the mock response sequence you would configure and what behavior your test should assert about the agent&#39;s recovery. Which of these scenarios is hardest to simulate with a mock and why?</p><h3 id="exercise-3-integration-test-architecture-hard" tabindex="-1">Exercise 3: Integration Test Architecture (Hard) <a class="header-anchor" href="#exercise-3-integration-test-architecture-hard" aria-label="Permalink to &quot;Exercise 3: Integration Test Architecture (Hard)&quot;">​</a></h3><p>Design an integration test that verifies the following end-to-end scenario: a user asks the agent to &quot;add error handling to the <code>process_data</code> function,&quot; the agent reads the file, identifies <code>unwrap()</code> calls, edits the file to replace them with proper error handling, and runs <code>cargo check</code> to verify the result compiles. Your test must not call any real LLM API. Describe: the workspace fixture setup (what files and Cargo.toml you need), the mock provider response sequence (what tool calls the model makes and in what order), the assertions you check after each step, and how you handle the fact that <code>cargo check</code> is a real subprocess. What is the boundary between what you mock and what you run for real?</p><h3 id="exercise-4-regression-test-design-for-safety-bypasses-medium" tabindex="-1">Exercise 4: Regression Test Design for Safety Bypasses (Medium) <a class="header-anchor" href="#exercise-4-regression-test-design-for-safety-bypasses-medium" aria-label="Permalink to &quot;Exercise 4: Regression Test Design for Safety Bypasses (Medium)&quot;">​</a></h3><p>A user reports that they were able to get the agent to read <code>/etc/passwd</code> by asking it to &quot;compare the format of /etc/passwd with your project&#39;s user config file.&quot; Design a regression test that: (a) reproduces this exact attack vector, (b) verifies the safety layer blocks the file read, (c) checks that the denial is communicated to the model as a tool error (not a crash), and (d) confirms the agent continues functioning after the denial. Generalize your test into a parameterized test suite that covers similar path traversal attacks using relative paths, symlinks, and URL-encoded paths.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>A complete agent testing strategy uses all eight techniques: unit tests, mock providers, snapshot tests, property tests, recording/replay, benchmarks, safety tests, and fixtures — each addressing a specific testing challenge</li><li>Use the decision framework to choose the right technique: unit tests for deterministic logic, mocks for loop testing, snapshots for output stability, property tests for edge cases, benchmarks for real-world quality, and safety tests for security boundaries</li><li>The CI pipeline runs in three tiers — fast deterministic tests on every push, integration tests on PRs, and benchmark evaluations on schedule — balancing coverage with speed and cost</li><li>Evolve your test suite alongside your agent: add regression tests for production bugs, re-record fixtures when changing models, and run benchmarks when changing prompts</li><li>The testing infrastructure is as valuable as the agent code itself — invest in good fixtures, mock providers, and CI pipelines from the start</li></ul>',48)])])}const g=t(a,[["render",i]]);export{p as __pageData,g as default};
